'use strict';

// scripts/repair-contract-schedules.js
// FINAL-CONTRACT-FIX
//
// One-shot data-repair script. Walks every contract whose payment schedule
// was generated by the legacy percentage-based applyTemplate path against a
// fixed-duration template (3/6/12-Month) and regenerates the schedule using
// the new unified generator.
//
// Idempotent: re-running on already-correct contracts is a no-op (the
// regenerated schedule matches the existing one within rounding, so no
// changes are written when invoice rows have not been paid; if invoice rows
// HAVE been paid, the contract is skipped with a warning).
//
// Repair scope:
//   - contract has payment_schedule_template_id pointing at a fixed-duration
//     template (duration_months IS NOT NULL)
//   - contract dates do NOT match the template duration in months, OR the
//     schedule snapshot was generated by the legacy path (snapshot rows
//     carry percent != null)
//   - NO contract_invoices rows are paid yet (status != 'paid'). If any
//     are paid, skip the contract — manual review needed.
//
// Per-contract repair:
//   1. Recompute total_value from generator math (monthly_rate × clean
//      months when applicable).
//   2. Delete pending/sent/cancelled/void/partial invoices for the contract.
//      Paid invoices are NEVER deleted (script aborts the contract if any).
//   3. Regenerate snapshot via generateContractSchedule.
//   4. Insert fresh invoice rows.
//   5. Update contract row (total_value, payment_schedule_snapshot).
//
// Usage:
//   node scripts/repair-contract-schedules.js                # dry-run (default)
//   node scripts/repair-contract-schedules.js --apply        # commit changes
//   node scripts/repair-contract-schedules.js --tenant <id>  # scope to one tenant
//
// Run AFTER migration 056 has been applied. Without 056 the
// payment_schedule_templates.duration_months column will not exist and the
// script will exit cleanly with an informative message.

const { pool } = require('../db');
const {
  generateContractSchedule,
  computeTotalValueFromSchedule,
  insertContractInvoices,
} = require('../utils/contracts');

const args = process.argv.slice(2);
const APPLY = args.includes('--apply');
const TENANT_FILTER = (() => {
  const i = args.indexOf('--tenant');
  if (i === -1) return null;
  const v = Number(args[i + 1]);
  return Number.isFinite(v) && v > 0 ? v : null;
})();

function log(...parts) {
  // eslint-disable-next-line no-console
  console.log('[repair-contract-schedules]', ...parts);
}

async function main() {
  log(APPLY ? 'APPLY mode — changes WILL be written' : 'DRY-RUN mode — no changes written (use --apply to commit)');
  if (TENANT_FILTER) log(`Scoped to tenant_id = ${TENANT_FILTER}`);

  // Pre-check: migration 056 applied?
  const colCheck = await pool.query(
    `SELECT 1 FROM information_schema.columns
       WHERE table_schema = 'public'
         AND table_name = 'payment_schedule_templates'
         AND column_name = 'duration_months'`
  );
  if (!colCheck.rows.length) {
    log('ERROR: payment_schedule_templates.duration_months column missing.');
    log('       Run migration 056_contract_schedule_fix.sql first, then re-run this script.');
    process.exit(1);
  }

  // Find candidate contracts.
  const params = [];
  let where = `c.payment_schedule_template_id IS NOT NULL
               AND t.duration_months IS NOT NULL`;
  if (TENANT_FILTER) {
    params.push(TENANT_FILTER);
    where += ` AND c.tenant_id = $${params.length}`;
  }

  const contracts = await pool.query(
    `SELECT c.id, c.tenant_id, c.contract_number, c.start_date, c.end_date,
            c.monthly_rate, c.total_value, c.security_deposit, c.currency_code,
            c.payment_schedule_template_id, c.payment_schedule_snapshot,
            c.status,
            t.duration_months, t.name AS template_name
       FROM contracts c
       JOIN payment_schedule_templates t ON t.id = c.payment_schedule_template_id
      WHERE ${where}
      ORDER BY c.id ASC`,
    params
  );

  log(`Found ${contracts.rows.length} candidate contract(s) using fixed-duration templates.`);

  let repaired = 0;
  let skippedNoChange = 0;
  let skippedPaid = 0;
  let errors = 0;

  for (const c of contracts.rows) {
    const tag = `[contract ${c.id} / ${c.contract_number}]`;

    // Has any invoice been paid? If so, skip — needs manual review.
    const paidCheck = await pool.query(
      `SELECT COUNT(*)::int AS c
         FROM contract_invoices
        WHERE contract_id = $1 AND status = 'paid'`,
      [c.id]
    );
    if (paidCheck.rows[0].c > 0) {
      log(`${tag} SKIP — has ${paidCheck.rows[0].c} paid invoice(s); manual review needed.`);
      skippedPaid += 1;
      continue;
    }

    // Generate the canonical schedule for this contract's dates/rate.
    const startDateStr = c.start_date instanceof Date
      ? c.start_date.toISOString().slice(0, 10)
      : String(c.start_date).slice(0, 10);
    const endDateStr = c.end_date instanceof Date
      ? c.end_date.toISOString().slice(0, 10)
      : String(c.end_date).slice(0, 10);
    const monthlyRate = Number(c.monthly_rate) || 0;
    const securityDeposit = Number(c.security_deposit) || 0;

    let generated;
    try {
      generated = generateContractSchedule({
        startDate: startDateStr,
        endDate: endDateStr,
        monthlyRate,
        securityDeposit,
      });
    } catch (err) {
      log(`${tag} ERROR — generator failed: ${err.message}`);
      errors += 1;
      continue;
    }

    const correctTotalValue = computeTotalValueFromSchedule({
      startDate: startDateStr, endDate: endDateStr, monthlyRate,
    });

    // Compare: does the existing schedule match? If row count + total_value
    // already match within rounding, no change needed.
    const existingSnap = Array.isArray(c.payment_schedule_snapshot)
      ? c.payment_schedule_snapshot
      : (typeof c.payment_schedule_snapshot === 'object' && c.payment_schedule_snapshot !== null
          ? c.payment_schedule_snapshot
          : []);
    const existingRentRowCount = existingSnap.filter(s =>
      // legacy snapshots have percent != null and no is_deposit flag.
      // New generator: is_deposit=false on rent rows.
      s && s.is_deposit !== true
    ).length;
    const newRentRowCount = generated.snapshot.filter(s => !s.is_deposit).length;
    const existingTotal = Number(c.total_value) || 0;
    const totalMatches = Math.abs(existingTotal - correctTotalValue) < 0.005;
    const countMatches = existingRentRowCount === newRentRowCount;

    if (totalMatches && countMatches) {
      log(`${tag} OK — schedule already correct (rent rows ${existingRentRowCount}, total ${existingTotal}). Skipping.`);
      skippedNoChange += 1;
      continue;
    }

    log(`${tag} REPAIR NEEDED:`);
    log(`         template: "${c.template_name}" (duration_months=${c.duration_months})`);
    log(`         dates:    ${startDateStr} → ${endDateStr}`);
    log(`         existing: total_value=${existingTotal}, rent rows=${existingRentRowCount}`);
    log(`         correct:  total_value=${correctTotalValue}, rent rows=${newRentRowCount}`);

    if (!APPLY) {
      continue;
    }

    // Apply: delete existing unpaid invoices, insert new ones, update contract.
    const client = await pool.connect();
    try {
      await client.query('BEGIN');

      // Sanity re-check inside transaction (catch race against operator activity).
      const reCheck = await client.query(
        `SELECT COUNT(*)::int AS c
           FROM contract_invoices
          WHERE contract_id = $1 AND status = 'paid'`,
        [c.id]
      );
      if (reCheck.rows[0].c > 0) {
        await client.query('ROLLBACK');
        log(`${tag} ABORTED — paid invoice appeared mid-flight; skipping.`);
        skippedPaid += 1;
        continue;
      }

      // Delete unpaid invoices.
      const del = await client.query(
        `DELETE FROM contract_invoices
           WHERE contract_id = $1
             AND status IN ('pending','sent','partial','cancelled','void')`,
        [c.id]
      );

      // Update contract: total_value, payment_schedule_snapshot.
      await client.query(
        `UPDATE contracts
            SET total_value = $1,
                payment_schedule_snapshot = $2::jsonb,
                updated_at = NOW()
          WHERE id = $3`,
        [correctTotalValue, JSON.stringify(generated.snapshot), c.id]
      );

      // Insert fresh invoices.
      await insertContractInvoices(client, {
        tenantId: c.tenant_id,
        contractId: c.id,
        currencyCode: c.currency_code,
        invoiceRows: generated.invoiceRows,
      });

      await client.query('COMMIT');
      log(`${tag} REPAIRED — deleted ${del.rowCount} stale invoice(s), inserted ${generated.invoiceRows.length} fresh invoice(s).`);
      repaired += 1;
    } catch (err) {
      await client.query('ROLLBACK').catch(() => {});
      log(`${tag} ERROR during repair: ${err.message}`);
      errors += 1;
    } finally {
      client.release();
    }
  }

  log('---');
  log(`Done. Repaired: ${repaired}. Skipped (already-correct): ${skippedNoChange}. Skipped (has paid invoices): ${skippedPaid}. Errors: ${errors}.`);

  await pool.end();
}

main().catch(err => {
  // eslint-disable-next-line no-console
  console.error('[repair-contract-schedules] FATAL:', err);
  process.exit(1);
});
